import React, { useEffect, useState, useCallback, useMemo } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme(); 
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ───────── 1. API Synchronization ───────── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      // Ensure history is always an array to prevent .map errors
      const data = Array.isArray(res.data) ? res.data : (res.data?.data || []);
      setHistory(data);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_PURGE: Proceed?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("DATA_PURGED");
    } catch (err) {
      toast.error("PURGE_ERROR");
    }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      toast.error("EXPORT_FAILED");
    }
  };

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  /* ───────── 2. Systematic Theme Calculation ───────── */
  // Forces CSS variable re-evaluation on theme toggle
  const themeStyles = useMemo(() => ({
    container: {
      background: 'var(--bg-primary)',
      color: 'var(--text-primary)',
    },
    modalOverlay: {
      background: isDark ? 'rgba(0, 0, 0, 0.95)' : 'rgba(255, 255, 255, 0.9)',
    }
  }), [isDark]);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_CORE_VAULT...</div>;

  return (
    <div className="reveal-node" style={{...containerStyle, ...themeStyles.container}}>
      {/* ── Page Header ── */}
      <div style={headerRow}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <Archive size={24} color="var(--accent-primary)"/>
          <h2 style={headerStyle}>STRATEGY_VAULT</h2>
        </div>
        <span style={vaultBadge}>{history.length} NODES_STORED</span>
      </div>

      {/* ── Strategy List ── */}
      <div style={listStyle}>
        {history.length === 0 ? (
          <div style={emptyState}>NO_DATA_FOUND: INITIALIZE_STRATEGY_CORE</div>
        ) : (
          history.map((item) => (
            <div key={item.id} className="vault-card" style={cardStyle}>
              <div style={{ flex: 1 }}>
                <div style={tagRow}>
                  <span style={metaText}><Calendar size={14}/> {new Date(item.created_at).toLocaleDateString()}</span>
                  <span style={riskTag}><ShieldCheck size={14}/> RISK: {item.risk_score}</span>
                </div>
                <h4 style={titleStyle}>{item.goal}</h4>
              </div>

              <div style={actionColumn}>
                <button onClick={() => setSelectedItem(item)} style={iconBtn} title="View"><Eye size={20}/></button>
                <button onClick={() => handleDownload(item)} style={iconBtn} title="Export"><Download size={20}/></button>
                <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Purge"><Trash2 size={20}/></button>
              </div>
            </div>
          ))
        )}
      </div>

      {/* ── Description Modal (OLED Fix) ── */}
      {selectedItem && (
        <div style={{...modalOverlay, ...themeStyles.modalOverlay}}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <span style={modalId}>NODE_DATA // ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}><X size={24}/></button>
            </div>
            
            <div style={modalBody}>
              <h3 style={modalTitle}>{selectedItem.goal}</h3>
              
              <div className="markdown-vault">
                <p style={labelSmall}><AlignLeft size={14}/> STRATEGIC_SUMMARY</p>
                <div style={widgetBox}>
                  <ReactMarkdown>{selectedItem.summary}</ReactMarkdown>
                </div>

                <p style={labelSmall}><AlignLeft size={14}/> AGENTIC_RATIONALE</p>
                <div style={widgetBox}>
                  <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        /* Deep Sync with theme.js Variables */
        .markdown-vault p { color: var(--text-primary) !important; font-size: 0.95rem; line-height: 1.6; margin-bottom: 1rem; }
        .markdown-vault h1, .markdown-vault h2 { color: var(--accent-primary); font-size: 1.1rem; margin-top: 1.2rem; text-transform: uppercase; font-weight: 800; }
        
        .vault-card { 
          background: var(--bg-input); 
          border: 1px solid var(--surface-border); 
          border-radius: 16px; 
          transition: all 0.2s ease; 
        }
        .vault-card:hover { border-color: var(--accent-primary) !important; transform: translateY(-2px); }
        
        .reveal-node { animation: fadeIn 0.4s ease-out; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

/* ─────────────────────────────── UI Constants ─────────────────────────────── */

const containerStyle = { padding: '3rem 1.5rem', maxWidth: '1000px', margin: '0 auto', minHeight: '100vh', transition: 'background 0.3s ease' };
